#include <stdio.h>
#include <string.h>

char* longestCommonPrefix(char** strs, int strsSize) {
    if (strsSize == 0) return "";
    char* shortest = strs[0];
    for (int i = 1; i < strsSize; i++) {
        if (strlen(strs[i]) < strlen(shortest)) {
            shortest = strs[i];
        }
    }
    for (int i = 0; i < strlen(shortest); i++) {
        for (int j = 0; j < strsSize; j++) {
            if (strs[j][i] != shortest[i]) {
                return shortest[i] = '\0', shortest;
            }
        }
    }
    return shortest;
}

int main() {
    char* strs[] = {"abc", "abcd", "abce", "abcf"};
    int strsSize = sizeof(strs) / sizeof(strs[0]);
    printf("%s\n", longestCommonPrefix(strs, strsSize));
    return 0;
}

