#include <iostream>
#include <vector>
#include <string>
using namespace std;

string longestCommonPrefix(vector<string>& strs) {
    if (strs.empty()) return "";
    string shortest = *min_element(strs.begin(), strs.end(), [](const string& a, const string& b) {
        return a.length() < b.length();
    });
    for (int i = 0; i < shortest.length(); i++) {
        for (const string& str : strs) {
            if (str[i] != shortest[i]) {
                return shortest.substr(0, i);
            }
        }
    }
    return shortest;
}

int main() {
    vector<string> strs = {"abc", "abcd", "abce", "abcf"};
    cout << longestCommonPrefix(strs) << endl;
    return 0;
}

