function longestCommonPrefix(strs) {
    if (!strs.length) return "";
    let shortest = strs.reduce((a, b) => a.length < b.length ? a : b);
    for (let i = 0; i < shortest.length; i++) {
        for (let str of strs) {
            if (str[i] !== shortest[i]) {
                return shortest.slice(0, i);
            }
        }
    }
    return shortest;
}

